};

// Admin Dashboard Component
const AdminDashboard = ({ onLogout }) => {
  const [contacts, setContacts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchContacts();
  }, []);

  const fetchContacts = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/contacts');
      const data = await response.json();
      
      if (data.success) {
        setContacts(data.data);
      } else {
        setError(data.message);
      }
    } catch (err) {
      setError('Failed to fetch contacts. Make sure the server is running.');
    }
    setLoading(false);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this message?')) {
      try {
        const response = await fetch(`http://localhost:5000/api/contacts/${id}`, {
          method: 'DELETE'
        });
        const data = await response.json();
        
        if (data.success) {
          setContacts(contacts.filter(contact => contact._id !== id));
        } else {
          alert('Failed to delete message');
        }
      } catch (err) {
        alert('Failed to delete message');
      }
    }
  };

  if (loading) {
    return (
      <section className="admin-section">
        <div className="container">
          <div className="admin-header">
            <h2>Admin Dashboard</h2>
            <button onClick={onLogout} className="btn btn-secondary">Logout</button>
          </div>
          <p>Loading...</p>
        </div>
      </section>
    );
  }

  return (
    <section className="admin-section">
      <div className="container">
        <div className="admin-header">
          <h2>Admin Dashboard - Contact Messages</h2>
          <button onClick={onLogout} className="btn btn-secondary">Logout</button>
        </div>
        
        {error && <div className="error-message">{error}</div>}
        
        {contacts.length === 0 ? (
          <p className="no-messages">No messages yet.</p>
        ) : (
          <div className="messages-list">
            {contacts.map((contact) => (
              <div key={contact._id} className="message-card">
                <div className="message-header">
                  <h3>{contact.name}</h3>
                  <span className="message-date">
                    {new Date(contact.dateSubmitted).toLocaleDateString('en-US', {
                      year: 'numeric',
                      month: 'short',
                      day: 'numeric',
                      hour: '2-digit',
                      minute: '2-digit'
                    })}
                  </span>
                </div>
                <p className="message-email"><strong>Email:</strong> {contact.email}</p>
                <p className="message-text">{contact.message}</p>
                <button onClick={() => handleDelete(contact._id)} className="btn-delete">Delete</button>
              </div>
            ))}
          </div>
        )}
      </div>
    </section>
  );
};

